window.FAQS = [{"q": "Why not just listen to a YouTube video?", "a": "Because you'd have to hunt for the clip, unmute, wait, rewind. <code>say-it kubectl</code> plays the right reading three times in 4 seconds. The site is here for when you're not at a terminal."}, {"q": "Why is the browser audio different from the CLI?", "a": "The CLI uses macOS's <code>say</code> with a tuned respelling. The site uses your browser's Web Speech API — voice and rules vary by OS. The CLI is canonical."}, {"q": "How is this different from a regular pronunciation dictionary?", "a": "This one's for the names engineers actually use — <code>kubectl</code>, <code>nginx</code>, <code>Pydantic</code>, <code>Knative</code>, <code>Ghostty</code>, <code>YAML</code>. Webster doesn't cover them; this does, with confidence tagging and a citable source where one exists."}, {"q": "Why is GIF \"jif\" here? I always say \"gif\".", "a": "Both are real. The dictionary picks the creator's stated reading as primary (\"jif\", per Wilhite at the 2013 Webby Awards) and surfaces \"gif\" as the alternate. Same pattern for SQL, JSON, char, regex."}, {"q": "Windows or Linux support?", "a": "On the roadmap. The dictionary itself is platform-agnostic; only the playback engine is platform-specific. PRs welcome."}, {"q": "How do I add a missing project?", "a": "Open a PR adding a row to <code>data/pronunciations.tsv</code>. See <code>CONTRIBUTING.md</code> for column format."}];

